#!/usr/bin/env node

/**
 * PostToolUse hook: protect agent-generated read-only paths.
 *
 * Blocks writes to:
 *   - any path under `src/generated/`  (regenerated by `npx power-apps add-data-source`)
 *   - any `power.config.json`          (regenerated by `npx power-apps init`)
 *   - any `vendor/<name>.tgz`          (sourced from upstream pa-wrap-tools)
 *
 * Manual edits to these files are silently lost on the next CLI run, so it's
 * almost always wrong. Block with a clear message pointing to the right tool.
 *
 * Exit codes: 0 pass, 2 block.
 */

const path = require('path');

function isWriteTool(t) {
  return t === 'Write' || t === 'Edit' || t === 'MultiEdit';
}

const PROTECTED = [
  {
    rx: /(^|\/)src\/generated\//,
    reason:
      '`src/generated/` is regenerated by `npx power-apps add-data-source`. Manual edits are lost on the next run. Add or refresh the data source via the CLI instead.',
  },
  {
    rx: /(^|\/)power\.config\.json$/,
    reason:
      '`power.config.json` is owned by `npx power-apps init`. Re-run `npx power-apps init --display-name <name> --environment-id <id> --non-interactive` to change environment binding.',
  },
  {
    rx: /(^|\/)vendor\/[^/]+\.tgz$/,
    reason:
      '`vendor/*.tgz` files are sourced from upstream `pa-wrap-tools`. Update them via the upstream repo, not by editing in-project.',
  },
];

let buf = '';
process.stdin.on('data', (c) => (buf += c));
process.stdin.on('end', () => {
  let input;
  try {
    input = JSON.parse(buf || '{}');
  } catch {
    process.exit(0);
  }
  const toolName = input.tool_name || input.toolName;
  const toolInput = input.tool_input || input.toolInput || {};
  if (!isWriteTool(toolName)) process.exit(0);
  const fp = toolInput.file_path || toolInput.filePath;
  if (typeof fp !== 'string') process.exit(0);

  const hit = PROTECTED.find(({ rx }) => rx.test(fp));
  if (!hit) process.exit(0);

  const rel = path.relative(process.cwd(), fp) || fp;
  process.stderr.write(`BLOCKED: protected path ${rel}\n\n  - ${hit.reason}\n`);
  process.exit(2);
});
